function solve(nums, target) {
    const n = nums.length;
    let minRemovals = Infinity;

    // Iterate through all possible subsets using a bitmask
    // There are 2^n subsets. Since n <= 40, 2^40 is too large.
    // However, the constraints are N <= 40. Let's re-examine the constraints.
    // 1 <= nums.length <= 40. 2^40 is too large for brute force subset enumeration (2^40 approx 10^12).

    // Given N <= 40, this suggests a meet-in-the-middle approach (2^(N/2)).
    // N/2 = 20, 2^20 is about 10^6, which is feasible.

    const mid = Math.floor(n / 2);
    const n1 = nums.slice(0, mid);
    const n2 = nums.slice(mid);

    // Map to store the XOR sums achievable from the first half, keyed by the number of elements used.
    // map1: Map<XOR_sum, min_count_used>
    // Since we want to minimize removals, we want to maximize elements kept.
    // Let's store: map1: Map<XOR_sum, max_elements_kept>
    const map1 = new Map();
    map1.set(0, 0); // XOR sum 0 is achievable by keeping 0 elements

    // Generate all XOR sums and max kept counts for the first half (n1)
    for (const num of n1) {
        const updates = new Map();
        for (const [currentXor, keptCount] of map1.entries()) {
            const newXor = currentXor ^ num;
            const newKeptCount = keptCount + 1;

            // Update map1 if this new XOR sum is better (more elements kept)
            const existingKeptCount = map1.get(newXor) || -1;
            if (newKeptCount > existingKeptCount) {
                updates.set(newXor, newKeptCount);
            }
        }
        // Merge updates into map1
        for (const [xor, count] of updates.entries()) {
            const existingKeptCount = map1.get(xor) || -1;
            if (count > existingKeptCount) {
                map1.set(xor, count);
            }
        }
    }


    // Map to store the XOR sums achievable from the second half, keyed by the number of elements used.
    // map2: Map<XOR_sum, max_elements_kept>
    const map2 = new Map();
    map2.set(0, 0); // XOR sum 0 is achievable by keeping 0 elements

    // Generate all XOR sums and max kept counts for the second half (n2)
    for (const num of n2) {
        const updates = new Map();
        for (const [currentXor, keptCount] of map2.entries()) {
            const newXor = currentXor ^ num;
            const newKeptCount = keptCount + 1;

            // Update map2 if this new XOR sum is better (more elements kept)
            const existingKeptCount = map2.get(newXor) || -1;
            if (newKeptCount > existingKeptCount) {
                updates.set(newXor, newKeptCount);
            }
        }
        // Merge updates into map2
        for (const [xor, count] of updates.entries()) {
            const existingKeptCount = map2.get(xor) || -1;
            if (count > existingKeptCount) {
                map2.set(xor, count);
            }
        }
    }

    // Combine results
    let maxKept = -1;

    // We need XOR_sum1 ^ XOR_sum2 = target, so XOR_sum2 = target ^ XOR_sum1
    for (const [xor1, count1] of map1.entries()) {
        const requiredXor2 = target ^ xor1;
        if (map2.has(requiredXor2)) {
            const count2 = map2.get(requiredXor2);
            const totalKept = count1 + count2;
            if (totalKept > maxKept) {
                maxKept = totalKept;
            }
        }
    }

    if (maxKept === -1) {
        // No subset results in the target XOR sum
        return -1;
    } else {
        // Minimum removals = Total elements - Maximum elements kept
        return n - maxKept;
    }
